import { test, expect } from '@playwright/test';
import path from 'path';
import { fileURLToPath } from 'url';
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/search.html')}`;
test.describe('Search Page E2E Tests', () => {
  let searchInput;
  let findButton;
  let results;
  test.beforeEach(async ({
    page
  }) => {
    await page.goto(localUrl, {
      waitUntil: 'domcontentloaded',
      timeout: 60000
    });
    searchInput = page.getByRole('textbox', {
      name: /search/i
    });
    await searchInput.waitFor({
      state: 'visible'
    });
    findButton = page.getByRole('button', {
      name: /find/i
    });
    await findButton.waitFor({
      state: 'visible'
    });
    results = page.locator('#results');
  });
  test('should have correct page title and initial element states', async ({
    page
  }) => {
    await expect(page).toHaveTitle('Search — AutoHeal Demo');
    await expect(searchInput).toBeVisible();
    await expect(findButton).toBeVisible();
    await expect(findButton).toBeDisabled();
    await expect(results).toBeEmpty();
  });
  test('should enable Find button when text is entered', async () => {
    await expect(findButton).toBeDisabled();
    await searchInput.fill('puppies');
    await expect(findButton).toBeEnabled();
  });
  test('should keep Find button disabled with whitespace-only input', async () => {
    await searchInput.fill('   ');
    await expect(findButton).toBeDisabled();
  });
  test('should display search results after clicking Find button', async () => {
    await searchInput.fill('kittens');
    await findButton.click();
    await expect(results).toHaveText('Found: kittens');
  });
  test('should clear results when searching for different term', async () => {
    await searchInput.fill('birds');
    await findButton.click();
    await expect(results).toHaveText('Found: birds');
    await searchInput.fill('fish');
    await findButton.click();
    await expect(results).toHaveText('Found: fish');
  });
  test('should not show results when searching with only whitespace', async () => {
    await searchInput.fill('   ');
    await expect(findButton).toBeDisabled();
    await expect(results).toBeEmpty();
  });
  test('should update results after multiple searches with same term', async () => {
    const searchTerm = 'hamsters';
    await searchInput.fill(searchTerm);
    await findButton.click();
    await expect(results).toHaveText(`Found: ${searchTerm}`);
    await searchInput.fill(searchTerm);
    await findButton.click();
    await expect(results).toHaveText(`Found: ${searchTerm}`);
  });
  test('button should toggle disabled state as input changes', async () => {
    await expect(findButton).toBeDisabled();
    await searchInput.fill('a');
    await expect(findButton).toBeEnabled();
    await searchInput.clear();
    await expect(findButton).toBeDisabled();
    await searchInput.fill('valid input');
    await expect(findButton).toBeEnabled();
  });
});
